import numpy as np

def consolidate_memories(
    memories: list,
    current_time: int,
    decay_rate: float,
    threshold: float,
    summary_fn
) -> tuple:
    if not memories:
        return [], None

    scores = []
    for m in memories:
        age = current_time - m['timestamp']
        score = m['importance'] * np.exp(-decay_rate * age)
        scores.append(float(score))

    kept = []
    to_merge = []
    for m, s in zip(memories, scores):
        if s >= threshold:
            kept.append(m)
        else:
            to_merge.append(m)

    if len(to_merge) < 2:
        return memories, None

    contents = [m['content'] for m in to_merge]
    summary_content = summary_fn(contents)
    mean_importance = float(np.mean([m['importance'] for m in to_merge]))
    summary_memory = {
        'content': summary_content,
        'importance': mean_importance,
        'timestamp': current_time
    }

    return kept, summary_memory
